parameters.jsCode:
const response = $input.first().json.output;
const inputData = $node["📋 Parse Input"].json;

try {
  const jsonMatch = response.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error("No JSON in response");
  const parsed = JSON.parse(jsonMatch[0]);

  return {
    json: {
      text: inputData.text,
      detected_language: parsed.language_code,
      detected_language_name: parsed.language_name,
      response_url: inputData.response_url,
      user_id: inputData.user_id,
      user_name: inputData.user_name
    }
  };
} catch (error) {
  return {
    json: {
      text: inputData.text,
      detected_language: 'en',
      detected_language_name: 'English',
      response_url: inputData.response_url,
      user_id: inputData.user_id,
      user_name: inputData.user_name
    }
  };
}

