const body = $input.first().json.body;
const text = body.text ? body.text.trim() : 'No text provided';

return {
  json: {
    text: text,
    user_id: body.user_id || 'unknown',
    user_name: body.user_name || 'unknown',
    channel_id: body.channel_id || 'unknown',
    response_url: body.response_url || null
  }
};

const response = $input.first().json.output;
const inputData = $node["📋 Parse Button Click"].json;

const flags = {
  en: "🇺🇸", fr: "🇫🇷", es: "🇪🇸", de: "🇩🇪",
  he: "🇮🇱", ar: "🇸🇦", ja: "🇯🇵", zh: "🇨🇳",
  ru: "🇷🇺", it: "🇮🇹", pt: "🇵🇹", ko: "🇰🇷"
};

const langNames = {
  en: "English", fr: "French", es: "Spanish", de: "German",
  he: "Hebrew", ar: "Arabic", ja: "Japanese", zh: "Chinese",
  ru: "Russian", it: "Italian", pt: "Portuguese", ko: "Korean"
};

const rtlLangs = ["he", "ar"];

const sourceLang = inputData.source_language;
const targetLang = inputData.target_language;
const sourceName = langNames[sourceLang] || sourceLang || "Unknown";
const targetName = langNames[targetLang] || targetLang || "Unknown";
const sourceFlag = flags[sourceLang] || "🌍";
const targetFlag = flags[targetLang] || "🌍";
const originalText = inputData.text || "";

// Strategy: try strict JSON parse first. If it fails (almost always due to
// unescaped quotes inside Hebrew acronyms like המנכ"ל, ארה"ב, צה"ל),
// fall back to extracting the "translation" field via a tolerant regex
// that grabs everything between `"translation": "` and the final `"}` of the object.
function extractTranslation(raw) {
  if (!raw) throw new Error("Empty LLM response");

  // Strip thinking/channel tags
  let str = raw.replace(/<\|?(?:think|channel|end_of_turn|start_of_turn)[^>]*\|?>/gi, "").trim();

  // Strip code fences if present
  str = str.replace(/^```(?:json)?\s*/i, "").replace(/\s*```$/i, "");

  // Find the start of the JSON object
  const objStart = str.indexOf("{");
  if (objStart === -1) throw new Error("No JSON object found");
  str = str.slice(objStart);

  // Try strict parse via balanced braces first
  try {
    let depth = 0, inStr = false, esc = false;
    for (let i = 0; i < str.length; i++) {
      const ch = str[i];
      if (esc) { esc = false; continue; }
      if (ch === "\\") { esc = true; continue; }
      if (ch === '"') { inStr = !inStr; continue; }
      if (inStr) continue;
      if (ch === "{") depth++;
      else if (ch === "}") {
        depth--;
        if (depth === 0) {
          const candidate = str.slice(0, i + 1);
          const parsed = JSON.parse(candidate);
          if (parsed.translation) return parsed.translation;
        }
      }
    }
  } catch (_) {
    // Fall through to tolerant extraction
  }

  // Tolerant extraction: locate "translation": " ... and grab until the closing
  // quote that's followed by optional whitespace and then } or , (end of value).
  const keyMatch = str.match(/"translation"\s*:\s*"/);
  if (!keyMatch) throw new Error("No translation field found");
  const valueStart = keyMatch.index + keyMatch[0].length;

  // Walk forward, find the LAST `"` before the final `}` of the object.
  // We look for the pattern: "<content>"<whitespace>}<end-of-string-ish>
  // Since translation is typically the last field, this works reliably.
  const tail = str.slice(valueStart);

  // Find the closing of the JSON object
  const lastBrace = tail.lastIndexOf("}");
  if (lastBrace === -1) throw new Error("No closing brace");

  // Walk back from the closing brace to find the closing quote of translation
  let closingQuote = -1;
  for (let i = lastBrace - 1; i >= 0; i--) {
    const ch = tail[i];
    if (ch === '"') { closingQuote = i; break; }
    if (!/\s/.test(ch) && ch !== ",") break;
  }
  if (closingQuote === -1) throw new Error("No closing quote for translation");

  let value = tail.slice(0, closingQuote);

  // Unescape standard JSON escapes that the model DID get right
  value = value
    .replace(/\\n/g, "\n")
    .replace(/\\r/g, "\r")
    .replace(/\\t/g, "\t")
    .replace(/\\"/g, '"')
    .replace(/\\\\/g, "\\")
    .replace(/\\u([0-9a-fA-F]{4})/g, (_, hex) => String.fromCharCode(parseInt(hex, 16)));

  return value;
}

let translation = "(Translation missing)";
try {
  translation = extractTranslation(response);
  if (rtlLangs.includes(targetLang)) {
    translation = `\u202B${translation}\u202C`;
  }
} catch (error) {
  const preview = (response || "").slice(0, 400).replace(/\n/g, " ");
  translation = `❌ Error: ${error.message}\n\nRaw preview:\n${preview}`;
}

const MAX = 2900;
const trim = (s) => (s.length > MAX ? s.slice(0, MAX) + "… [truncated]" : s);

const payload = {
  replace_original: true,
  blocks: [
    { type: "header", text: { type: "plain_text", text: "🌐 Translation Complete" } },
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*📝 Original (${sourceFlag} ${sourceName}):*\n\`\`\`${trim(originalText)}\`\`\``
      }
    },
    {
      type: "section",
      text: {
        type: "mrkdwn",
        text: `*${targetFlag} ${targetName} Translation:*\n\`\`\`${trim(translation)}\`\`\``
      }
    }
  ]
};

return {
  json: {
    response_url: inputData.response_url,
    slack_payload: payload
  }
};

// Parse Slack interactive payload
const body = $input.first().json.body;
const payload = JSON.parse(body.payload);

// Case 1: Triggered via the "Translate this" menu shortcut
if (payload.type === 'message_action') {
  return {
    json: {
      text: payload.message.text,
      target_language: 'en',
      source_language: 'auto',
      response_url: payload.response_url,
      user_id: payload.user.id,
      user_name: payload.user.name,
      trigger_type: 'shortcut'
    }
  };
}

// Case 2: Triggered via a button click
const value = payload.actions[0].value;
const parts = value.split('|');

return {
  json: {
    target_language: parts[0],
    source_language: parts[1],
    text: parts.slice(2).join('|'),
    response_url: payload.response_url,
    user_id: payload.user.id,
    user_name: payload.user.name,
    trigger_type: 'button'
  }
};

